-- Enhanced Texas Consulting Agreement Template v2
-- Improvements: TX B&C Code Ch. 35, Non-Solicitation, Prompt Payment Act, DTPA Waiver,
-- Enhanced IP, Data Breach Act, Licensing, LOL with case law, Venue, Franchise Tax

UPDATE contract_templates SET
  version = 2,
  title = 'Consulting Services Agreement (Texas)',
  preamble = 'This Consulting Services Agreement (the "Agreement") is entered into as of {{effective_date}} (the "Effective Date"), by and between {{party_a_company}}, a {{party_a_entity_type}} organized under the laws of the State of Texas, with its principal place of business at {{party_a_address}} ("Client"), and {{party_b_company}}, a {{party_b_entity_type}}, with its principal place of business at {{party_b_address}} ("Consultant"). Client and Consultant may be referred to individually as a "Party" and collectively as the "Parties."',
  recitals = 'WHEREAS, Client desires to engage Consultant to provide professional consulting services as described herein;

WHEREAS, Consultant represents that Consultant has the requisite expertise, qualifications, and any required professional licenses under the Texas Occupations Code to provide such services;

WHEREAS, the Parties intend to establish an independent contractor relationship in accordance with Texas law;

NOW, THEREFORE, in consideration of the mutual covenants and promises contained herein, and for other good and valuable consideration, the receipt and sufficiency of which are hereby acknowledged, the Parties agree as follows:',
  clauses = '[
  {
    "id": "engagement_scope",
    "title": "1. ENGAGEMENT AND SCOPE OF SERVICES",
    "content": "1.1 Engagement. Client hereby engages Consultant, and Consultant hereby accepts such engagement, to provide the professional consulting services described in Exhibit A or {{services_description}} (the \"Services\"), subject to the terms and conditions of this Agreement.\n\n1.2 Standard of Performance. Consultant shall perform the Services in a professional and workmanlike manner, consistent with generally accepted industry standards for similar services in Texas, and in compliance with all applicable federal, state, and local laws, including applicable provisions of the Texas Occupations Code.\n\n1.3 Professional Licensing. Consultant represents and warrants that Consultant holds all licenses, certifications, and registrations required under the Texas Occupations Code and other applicable law to perform the Services. Consultant shall maintain such licenses in good standing throughout the term of this Agreement and shall promptly notify Client of any suspension, revocation, or material change in licensing status.\n\n1.4 Deliverables. Consultant shall produce and deliver any work product, reports, analyses, or other deliverables (\"Deliverables\") specified in Exhibit A or {{services_description}} in accordance with the timeline and specifications set forth therein.\n\n1.5 Client Cooperation. Client shall provide Consultant with reasonable and timely access to personnel, information, systems, and resources reasonably necessary for Consultant to perform the Services. Consultant shall not be liable for delays caused by Client''s failure to provide such access.\n\n1.6 Changes to Scope. Any changes to the Services, Deliverables, timeline, or specifications must be agreed in a written amendment or change order signed by authorized representatives of both Parties.",
    "type": "standard",
    "order": 1
  },
  {
    "id": "fees_payment",
    "title": "2. FEES, INVOICING, AND PAYMENT",
    "content": "2.1 Fees. Client shall pay Consultant the fees set forth in Exhibit A or as follows: (a) a fixed fee of {{payment_amount}}; and/or (b) an hourly rate of {{hourly_rate}}.\n\n2.2 Invoicing. Consultant shall submit detailed invoices in accordance with Exhibit A, or if not specified, monthly in arrears. Each invoice shall include: (a) a description of Services performed; (b) dates of performance; (c) hours worked (if applicable); (d) itemized expenses (if applicable); and (e) applicable taxes.\n\n2.3 Texas Prompt Payment Act Compliance. Client acknowledges that payments to Consultant may be subject to the Texas Prompt Payment Act (Texas Government Code Chapter 2251 for government contracts or Texas Business & Commerce Code Chapter 35 for commercial contracts). Unless otherwise specified in writing:\n(a) For private commercial transactions, Client shall pay undisputed invoice amounts within thirty (30) days of receipt of a proper invoice.\n(b) Late payments shall accrue interest at the rate of one and one-half percent (1.5%) per month, or the maximum rate permitted by Texas Finance Code Section 302.001, whichever is less.\n(c) If Client disputes any portion of an invoice, Client shall notify Consultant in writing within fifteen (15) days of receipt, specifying the disputed amount and basis for dispute, and shall timely pay all undisputed amounts.\n\n2.4 Expenses. Unless expressly pre-approved in writing by Client, Consultant shall bear all expenses incurred in performing the Services. Pre-approved expenses shall be reimbursed at cost upon submission of reasonable documentation.\n\n2.5 Taxes. Consultant is solely responsible for all federal, state, and local taxes arising from compensation received under this Agreement. Texas does not impose a state individual income tax. Client shall not withhold payroll taxes, social security, Medicare, or unemployment insurance for Consultant. Client may report payments to Consultant on IRS Form 1099 as required by law.\n\n2.6 Suspension for Non-Payment. If Client fails to pay undisputed amounts when due, Consultant may, after providing ten (10) days'' written notice, suspend performance of the Services until all outstanding amounts are paid in full.",
    "type": "standard",
    "order": 2
  },
  {
    "id": "consultant_status",
    "title": "3. INDEPENDENT CONTRACTOR STATUS",
    "content": "3.1 Independent Contractor. Consultant is an independent contractor and not an employee, partner, joint venturer, agent, or representative of Client. Nothing in this Agreement shall be construed to create an employment relationship, partnership, or agency.\n\n3.2 Control and Autonomy. Consultant shall determine the manner, method, and means of performing the Services, subject to the requirements of this Agreement. Consultant retains the right to set Consultant''s own work hours, work location, and work methods.\n\n3.3 Texas Classification. The Parties intend that Consultant be properly classified as an independent contractor under all applicable Texas law, including:\n(a) Texas Labor Code Chapter 21 (Texas Commission on Human Rights Act);\n(b) Texas Workforce Commission guidelines and regulations;\n(c) Texas Unemployment Compensation Act (Texas Labor Code Chapter 201); and\n(d) Texas Workers'' Compensation Act (Texas Labor Code Title 5).\n\n3.4 No Employee Benefits. Consultant is not entitled to, and hereby waives any claim to, any Client employee benefits, including but not limited to health insurance, retirement plans, paid time off, workers'' compensation coverage (unless separately arranged), or any other fringe benefits.\n\n3.5 Tools and Equipment. Consultant shall provide Consultant''s own tools, equipment, supplies, and workspace necessary to perform the Services, unless otherwise agreed in writing.\n\n3.6 Other Engagements. Consultant may provide services to other clients and customers, provided such engagements do not create a conflict of interest or interfere with Consultant''s obligations under this Agreement.\n\n3.7 Responsibility for Personnel. If Consultant uses employees, agents, or subcontractors to perform any portion of the Services, Consultant shall be solely responsible for their compensation, taxes, benefits, and compliance with applicable employment laws.",
    "type": "standard",
    "order": 3
  },
  {
    "id": "term_termination",
    "title": "4. TERM AND TERMINATION",
    "content": "4.1 Term. This Agreement commences on the Effective Date and shall continue until {{expiration_date}}, or if no expiration date is specified, until the Services are completed, unless earlier terminated in accordance with this Section 4.\n\n4.2 Termination for Convenience. Either Party may terminate this Agreement for any reason or no reason upon {{notice_period}} days'' prior written notice to the other Party (or thirty (30) days if not specified).\n\n4.3 Termination for Cause. Either Party may terminate this Agreement immediately upon written notice if the other Party:\n(a) Materially breaches this Agreement and fails to cure such breach within fifteen (15) days after receiving written notice specifying the breach;\n(b) Becomes insolvent, makes an assignment for the benefit of creditors, or files or has filed against it a petition in bankruptcy;\n(c) Commits fraud, gross negligence, or willful misconduct; or\n(d) Loses any license, certification, or authorization required to perform the Services.\n\n4.4 Effect of Termination. Upon termination or expiration of this Agreement:\n(a) Consultant shall immediately cease performing the Services;\n(b) Consultant shall deliver to Client all completed and partially completed Work Product, Deliverables, and Client Materials;\n(c) Client shall pay Consultant for all Services properly performed and approved expenses incurred through the effective date of termination;\n(d) Each Party shall return or, at the other Party''s option, securely destroy the other Party''s Confidential Information;\n(e) Consultant shall cooperate with Client to ensure an orderly transition of the Services.\n\n4.5 Survival. The following provisions shall survive termination or expiration of this Agreement: Sections 5 (Intellectual Property), 6 (Confidentiality), 7 (Non-Solicitation), 8 (Representations and Warranties), 9 (Limitation of Liability), 10 (Indemnification), 11 (DTPA Waiver), and 12 (General Provisions).",
    "type": "standard",
    "order": 4
  },
  {
    "id": "intellectual_property",
    "title": "5. INTELLECTUAL PROPERTY",
    "content": "5.1 Definitions.\n(a) \"Work Product\" means all Deliverables, inventions, improvements, developments, discoveries, works of authorship, designs, documentation, reports, analyses, software, code, data, and other materials (whether tangible or intangible) that are conceived, created, developed, authored, or reduced to practice by Consultant, alone or with others, in the course of performing the Services.\n(b) \"Background IP\" means intellectual property owned or controlled by a Party prior to the Effective Date, or developed by a Party independently of this Agreement without use of the other Party''s Confidential Information.\n\n5.2 Assignment of Work Product. Subject to Client''s full payment of all amounts due under this Agreement:\n(a) Consultant hereby irrevocably assigns, transfers, and conveys to Client all right, title, and interest in and to the Work Product, including all patents, copyrights, trade secrets, trademarks, and other intellectual property rights therein, throughout the world and in perpetuity.\n(b) To the extent any Work Product constitutes a \"work made for hire\" under the U.S. Copyright Act (17 U.S.C. Section 101), Client shall be deemed the author thereof.\n(c) To the extent any rights cannot be assigned, Consultant hereby grants Client an exclusive, perpetual, irrevocable, worldwide, royalty-free license to use, reproduce, modify, distribute, display, and create derivative works from such Work Product.\n\n5.3 Texas IP Provisions. This assignment is made in accordance with Texas law, including Texas Business & Commerce Code provisions governing intellectual property transfers. Consultant acknowledges that Client may seek to patent inventions arising from the Work Product and agrees to execute any patent applications or assignments reasonably requested by Client.\n\n5.4 Further Assurances. Consultant shall execute and deliver any documents, assignments, applications, or other instruments, and take any actions, reasonably requested by Client to perfect, register, maintain, or enforce Client''s rights in the Work Product. Consultant hereby irrevocably appoints Client as Consultant''s attorney-in-fact to execute such documents if Consultant fails or refuses to do so.\n\n5.5 Background IP License. To the extent any Consultant Background IP is incorporated into or necessary to use the Work Product, Consultant hereby grants Client a non-exclusive, perpetual, irrevocable, worldwide, royalty-free, fully paid-up license (with the right to sublicense) to use, reproduce, modify, distribute, display, and create derivative works from such Background IP, solely in connection with Client''s use of the Work Product.\n\n5.6 Client Materials. Client retains all rights in materials, data, content, and other items provided by Client to Consultant (\"Client Materials\"). Client grants Consultant a limited, non-exclusive, revocable license to use Client Materials solely to perform the Services.\n\n5.7 Moral Rights Waiver. To the fullest extent permitted under applicable law, including the Visual Artists Rights Act (17 U.S.C. Section 106A) and any similar state laws, Consultant hereby irrevocably waives and agrees not to assert any \"moral rights,\" \"droit moral,\" or similar rights in the Work Product.\n\n5.8 Third-Party Materials. Consultant shall not incorporate any open source software, third-party code, or other third-party materials into the Work Product without Client''s prior written consent. If approved, Consultant shall identify all such materials and provide copies of applicable licenses.",
    "type": "negotiable",
    "order": 5
  },
  {
    "id": "confidentiality",
    "title": "6. CONFIDENTIALITY AND DATA PROTECTION",
    "content": "6.1 Definition of Confidential Information. \"Confidential Information\" means any and all non-public information disclosed by one Party (\"Disclosing Party\") to the other Party (\"Receiving Party\"), whether disclosed orally, visually, electronically, or in writing, that is designated as confidential or that reasonably should be understood to be confidential given the nature of the information and circumstances of disclosure. Confidential Information includes, without limitation:\n(a) Trade secrets as defined under the Texas Uniform Trade Secrets Act (Texas Civil Practice and Remedies Code Chapter 134A);\n(b) Business plans, financial information, pricing, customer lists, and vendor information;\n(c) Technical data, software, source code, algorithms, and product plans;\n(d) Personal information as defined under applicable privacy laws.\n\n6.2 Obligations. The Receiving Party shall:\n(a) Use the Disclosing Party''s Confidential Information solely to perform its obligations or exercise its rights under this Agreement;\n(b) Not disclose Confidential Information to any third party except as expressly permitted herein;\n(c) Protect Confidential Information using at least the same degree of care used to protect its own confidential information of like importance, and in no event less than reasonable care;\n(d) Limit access to Confidential Information to those employees, agents, and contractors who have a need to know and who are bound by confidentiality obligations at least as protective as those herein.\n\n6.3 Exclusions. Confidential Information does not include information that the Receiving Party can demonstrate by competent evidence:\n(a) Is or becomes publicly available through no fault of the Receiving Party;\n(b) Was lawfully known to the Receiving Party without restriction before disclosure;\n(c) Is lawfully received from a third party without breach of any confidentiality obligation;\n(d) Is independently developed by the Receiving Party without use of or reference to the Disclosing Party''s Confidential Information.\n\n6.4 Compelled Disclosure. If the Receiving Party is required by law, regulation, subpoena, or court order to disclose Confidential Information, it shall (to the extent legally permitted) provide prompt written notice to the Disclosing Party and reasonably cooperate in seeking a protective order. The Receiving Party shall disclose only the minimum Confidential Information legally required.\n\n6.5 Texas Data Breach Notification Act Compliance. If either Party becomes aware of a breach of security affecting personal information (as defined in Texas Business & Commerce Code Section 521.002) of the other Party or its customers, the affected Party shall:\n(a) Notify the other Party without unreasonable delay, and in no event later than sixty (60) days after discovery;\n(b) Provide reasonable cooperation in investigating the breach and mitigating potential harm;\n(c) Comply with all notification requirements under Texas Business & Commerce Code Chapter 521.\n\n6.6 Return or Destruction. Upon termination of this Agreement or upon request, each Party shall promptly return or securely destroy the other Party''s Confidential Information, except for copies retained as required by law or bona fide document retention policies (which shall remain subject to this Section 6).\n\n6.7 Defend Trade Secrets Act Notice. Pursuant to 18 U.S.C. Section 1833(b), an individual shall not be held criminally or civilly liable under any federal or state trade secret law for the disclosure of a trade secret made: (a) in confidence to a government official or attorney solely for the purpose of reporting or investigating a suspected violation of law; or (b) in a complaint or other document filed in a lawsuit or other proceeding, if such filing is made under seal.\n\n6.8 Injunctive Relief. The Parties acknowledge that a breach of this Section 6 may cause irreparable harm for which monetary damages would be inadequate. The non-breaching Party shall be entitled to seek injunctive or equitable relief, in addition to any other remedies, without the necessity of proving actual damages or posting a bond, to the extent permitted under Texas law.",
    "type": "standard",
    "order": 6
  },
  {
    "id": "non_solicitation",
    "title": "7. NON-SOLICITATION",
    "content": "7.1 Texas Non-Compete Law. The Parties acknowledge that Texas Business & Commerce Code Section 15.50 et seq. governs the enforceability of covenants not to compete in Texas. The Parties agree that this Agreement does not contain a non-compete provision that would restrict Consultant from engaging in any lawful profession, trade, or business.\n\n7.2 Non-Solicitation of Employees. During the term of this Agreement and for a period of {{non_solicit_period}} months (or twelve (12) months if not specified) following termination or expiration, Consultant shall not, directly or indirectly, solicit, recruit, hire, or attempt to solicit, recruit, or hire any employee of Client with whom Consultant had material contact or about whom Consultant received Confidential Information during the course of this Agreement.\n\n7.3 Non-Solicitation of Customers. During the term of this Agreement and for a period of {{non_solicit_period}} months (or twelve (12) months if not specified) following termination or expiration, Consultant shall not, directly or indirectly, solicit, induce, or attempt to solicit or induce any customer or client of Client with whom Consultant had material contact during the course of this Agreement to:\n(a) Cease or reduce doing business with Client; or\n(b) Purchase or obtain services competitive with Client''s services from any person or entity other than Client.\n\n7.4 Reasonableness. The Parties agree that the non-solicitation restrictions set forth in this Section 7 are reasonable in scope, duration, and geographic area, are supported by adequate consideration including access to Confidential Information and business relationships, and are necessary to protect Client''s legitimate business interests, including its confidential customer relationships, trade secrets, and goodwill.\n\n7.5 Enforceability Under Texas Law. If any court of competent jurisdiction determines that any provision of this Section 7 is unenforceable, the Parties agree that such court may reform the provision to the minimum extent necessary to make it enforceable, consistent with Texas Business & Commerce Code Section 15.51.\n\n7.6 Exceptions. Nothing in this Section 7 shall prohibit Consultant from:\n(a) Responding to unsolicited inquiries from employees or customers;\n(b) Hiring employees who independently apply for employment without solicitation;\n(c) Engaging in general advertising or recruitment efforts not specifically targeted at Client''s employees or customers.",
    "type": "negotiable",
    "order": 7
  },
  {
    "id": "representations_warranties",
    "title": "8. REPRESENTATIONS AND WARRANTIES",
    "content": "8.1 Mutual Representations. Each Party represents and warrants that:\n(a) It has full right, power, and authority to enter into and perform this Agreement;\n(b) This Agreement constitutes a legal, valid, and binding obligation enforceable in accordance with its terms;\n(c) Its execution and performance of this Agreement will not violate any other agreement to which it is bound or any applicable law.\n\n8.2 Consultant Representations. Consultant represents and warrants that:\n(a) Consultant has the requisite skills, qualifications, and experience to perform the Services in a professional manner;\n(b) Consultant holds all licenses, certifications, and registrations required under the Texas Occupations Code and other applicable law to perform the Services;\n(c) The Services will be performed in a professional and workmanlike manner consistent with generally accepted industry standards;\n(d) The Work Product will be original and will not infringe or misappropriate any third-party intellectual property rights;\n(e) Consultant will comply with all applicable federal, state, and local laws, regulations, and ordinances in performing the Services;\n(f) Consultant is not bound by any agreement that would prevent or restrict Consultant''s performance under this Agreement.\n\n8.3 Client Representations. Client represents and warrants that:\n(a) Client has the rights necessary to provide Client Materials to Consultant for use as contemplated in this Agreement;\n(b) Client Materials, when used as directed by Client, will not infringe or misappropriate any third-party intellectual property rights.\n\n8.4 Disclaimer. EXCEPT AS EXPRESSLY SET FORTH IN THIS AGREEMENT, NEITHER PARTY MAKES ANY OTHER REPRESENTATIONS OR WARRANTIES, EXPRESS, IMPLIED, STATUTORY, OR OTHERWISE, INCLUDING ANY IMPLIED WARRANTIES OF MERCHANTABILITY, FITNESS FOR A PARTICULAR PURPOSE, TITLE, OR NON-INFRINGEMENT, TO THE MAXIMUM EXTENT PERMITTED BY APPLICABLE LAW.\n\n8.5 No Guaranteed Outcomes. Consultant does not guarantee any specific business, financial, legal, or regulatory outcome from the Services unless expressly stated in a signed writing by Consultant.",
    "type": "standard",
    "order": 8
  },
  {
    "id": "limitation_of_liability",
    "title": "9. LIMITATION OF LIABILITY",
    "content": "9.1 Exclusion of Certain Damages. TO THE MAXIMUM EXTENT PERMITTED BY APPLICABLE LAW, IN NO EVENT SHALL EITHER PARTY BE LIABLE TO THE OTHER PARTY FOR ANY INDIRECT, INCIDENTAL, CONSEQUENTIAL, SPECIAL, EXEMPLARY, OR PUNITIVE DAMAGES, OR FOR ANY LOSS OF PROFITS, REVENUE, BUSINESS, GOODWILL, DATA, OR ANTICIPATED SAVINGS, ARISING OUT OF OR RELATED TO THIS AGREEMENT OR THE SERVICES, REGARDLESS OF THE THEORY OF LIABILITY (WHETHER IN CONTRACT, TORT, STRICT LIABILITY, OR OTHERWISE), EVEN IF SUCH PARTY HAS BEEN ADVISED OF THE POSSIBILITY OF SUCH DAMAGES.\n\n9.2 Liability Cap. TO THE MAXIMUM EXTENT PERMITTED BY APPLICABLE LAW, EACH PARTY''S TOTAL AGGREGATE LIABILITY ARISING OUT OF OR RELATED TO THIS AGREEMENT SHALL NOT EXCEED THE GREATER OF: (A) THE TOTAL FEES ACTUALLY PAID OR PAYABLE BY CLIENT TO CONSULTANT UNDER THIS AGREEMENT DURING THE TWELVE (12) MONTHS IMMEDIATELY PRECEDING THE EVENT GIVING RISE TO THE CLAIM; OR (B) {{liability_cap}} (OR $50,000 IF NOT SPECIFIED).\n\n9.3 Texas Law Considerations. The Parties acknowledge that Texas courts generally enforce contractual limitations of liability when freely negotiated between commercial parties of relatively equal bargaining power. See, e.g., Dresser Industries, Inc. v. Page Petroleum, Inc., 853 S.W.2d 505 (Tex. 1993); Valero Marketing & Supply Co. v. Kalama Int''l, 51 S.W.3d 345 (Tex. App. 2001).\n\n9.4 Exceptions to Limitations. The limitations set forth in Sections 9.1 and 9.2 shall not apply to:\n(a) A Party''s indemnification obligations under Section 10;\n(b) A Party''s breach of intellectual property provisions under Section 5;\n(c) A Party''s breach of confidentiality obligations under Section 6;\n(d) A Party''s gross negligence, willful misconduct, or fraud;\n(e) Claims for personal injury or death caused by a Party''s negligence;\n(f) Liability that cannot be limited or excluded under applicable Texas law.\n\n9.5 Allocation of Risk. THE PARTIES ACKNOWLEDGE THAT THE FEES REFLECT THE ALLOCATION OF RISK SET FORTH IN THIS AGREEMENT AND THAT NEITHER PARTY WOULD ENTER INTO THIS AGREEMENT WITHOUT THE LIMITATIONS SET FORTH IN THIS SECTION 9. THESE LIMITATIONS SHALL APPLY REGARDLESS OF WHETHER ANY LIMITED REMEDY FAILS OF ITS ESSENTIAL PURPOSE.\n\n9.6 Statute of Limitations. Any claim arising out of or related to this Agreement must be brought within two (2) years after the cause of action accrues, or within such shorter period as may be required by applicable Texas law.",
    "type": "negotiable",
    "order": 9
  },
  {
    "id": "indemnification",
    "title": "10. INDEMNIFICATION",
    "content": "10.1 Consultant Indemnification. Consultant shall defend, indemnify, and hold harmless Client and its officers, directors, employees, agents, successors, and assigns (collectively, \"Client Indemnitees\") from and against any and all third-party claims, demands, actions, suits, losses, damages, liabilities, costs, and expenses (including reasonable attorneys'' fees and court costs) (\"Claims\") arising out of or related to:\n(a) Consultant''s negligence, gross negligence, or willful misconduct in performing the Services;\n(b) Consultant''s breach of any representation, warranty, or obligation under this Agreement;\n(c) Any claim that the Work Product or Consultant''s Background IP incorporated therein infringes or misappropriates any third-party intellectual property rights (excluding claims arising solely from Client Materials or Client''s specifications);\n(d) Any claim arising from Consultant''s failure to comply with applicable laws, including licensing requirements under the Texas Occupations Code;\n(e) Any claim by Consultant''s employees, agents, or subcontractors relating to their employment or engagement by Consultant.\n\n10.2 Client Indemnification. Client shall defend, indemnify, and hold harmless Consultant and its officers, directors, employees, agents, successors, and assigns from and against any and all Claims arising out of or related to:\n(a) Client''s negligence, gross negligence, or willful misconduct;\n(b) Client''s breach of any representation, warranty, or obligation under this Agreement;\n(c) Any claim that Client Materials infringe or misappropriate any third-party intellectual property rights;\n(d) Client''s use of the Work Product in a manner not authorized by this Agreement.\n\n10.3 Indemnification Procedure. The Party seeking indemnification (\"Indemnified Party\") shall:\n(a) Promptly notify the indemnifying Party (\"Indemnifying Party\") in writing of any Claim (provided that failure to provide timely notice shall not relieve the Indemnifying Party of its obligations except to the extent materially prejudiced by such failure);\n(b) Allow the Indemnifying Party to assume sole control of the defense and settlement of the Claim;\n(c) Provide reasonable cooperation and assistance to the Indemnifying Party at the Indemnifying Party''s expense.\n\n10.4 Settlement. The Indemnifying Party shall not settle any Claim in a manner that admits liability or imposes any obligation on the Indemnified Party without the Indemnified Party''s prior written consent.\n\n10.5 Exclusive Remedy. This Section 10 states the entire liability of the Indemnifying Party and the exclusive remedy of the Indemnified Party with respect to Claims covered by this Section 10.",
    "type": "negotiable",
    "order": 10
  },
  {
    "id": "dtpa_waiver",
    "title": "11. TEXAS DECEPTIVE TRADE PRACTICES ACT WAIVER",
    "content": "11.1 DTPA Waiver. TO THE EXTENT PERMITTED BY LAW, CONSULTANT HEREBY WAIVES THE PROVISIONS OF THE TEXAS DECEPTIVE TRADE PRACTICES-CONSUMER PROTECTION ACT (TEXAS BUSINESS & COMMERCE CODE CHAPTER 17, SUBCHAPTER E) (THE \"DTPA\"), OTHER THAN SECTION 17.555 (WHICH PROHIBITS WAIVER OF CONSUMER CLAIMS ARISING FROM CERTAIN UNCONSCIONABLE ACTIONS OR MISREPRESENTATIONS OF MATERIAL FACT). THIS WAIVER IS GIVEN VOLUNTARILY AND KNOWINGLY BY CONSULTANT.\n\n11.2 Waiver Requirements. Consultant acknowledges and represents that:\n(a) Consultant is not in a significantly disparate bargaining position with respect to Client;\n(b) Consultant was represented by legal counsel in connection with the negotiation and execution of this Agreement, OR Consultant had a reasonable opportunity to consult with legal counsel and knowingly chose not to do so;\n(c) The consideration for this Agreement exceeds $500,000.00, OR if the consideration is less than $500,000.00, Consultant has been represented by legal counsel in seeking or acquiring goods or services under this Agreement.\n\n11.3 Scope of Waiver. This DTPA waiver applies only to the extent permitted by Texas Business & Commerce Code Section 17.42 and does not waive claims that cannot be waived under applicable law, including claims based on unconscionable actions and misrepresentations of material fact that the consumer was unable to reasonably discover.\n\n11.4 Client DTPA Waiver. To the extent Client qualifies as a \"consumer\" under the DTPA and has met the requirements of Section 17.42, Client may similarly waive DTPA claims against Consultant by providing written notice to Consultant.\n\n11.5 Alternative: If DTPA Waiver Not Applicable. If the requirements for a valid DTPA waiver under Section 17.42 are not met, then this Section 11 shall be deemed not to apply, and both Parties shall retain any rights and remedies available under the DTPA. In such case, the validity and enforceability of the remaining provisions of this Agreement shall not be affected.",
    "type": "optional",
    "order": 11
  },
  {
    "id": "insurance",
    "title": "12. INSURANCE",
    "content": "12.1 Consultant Insurance. During the term of this Agreement, Consultant shall obtain and maintain, at Consultant''s own expense, the following insurance coverage:\n(a) Commercial General Liability Insurance with limits of at least $1,000,000 per occurrence and $2,000,000 in the aggregate;\n(b) Professional Liability (Errors & Omissions) Insurance with limits of at least $1,000,000 per claim and in the aggregate, if applicable to the Services;\n(c) Workers'' Compensation Insurance as required by Texas law (if Consultant has employees); and\n(d) Any additional insurance required by law or reasonably requested by Client in writing.\n\n12.2 Insurance Requirements. All insurance policies shall:\n(a) Be issued by insurance companies with an A.M. Best rating of at least A- VII or equivalent;\n(b) Provide that coverage shall not be cancelled, materially modified, or non-renewed without at least thirty (30) days'' prior written notice to Client.\n\n12.3 Certificates of Insurance. Upon request, Consultant shall provide Client with certificates of insurance evidencing the required coverage.\n\n12.4 No Limitation of Liability. Consultant''s maintenance of insurance shall not be construed to limit or satisfy Consultant''s indemnification obligations or liability under this Agreement.",
    "type": "standard",
    "order": 12
  },
  {
    "id": "general_provisions",
    "title": "13. GENERAL PROVISIONS",
    "content": "13.1 Governing Law. This Agreement and any dispute arising out of or related to this Agreement shall be governed by and construed in accordance with the laws of the State of Texas, without regard to its conflict of laws principles.\n\n13.2 Venue and Jurisdiction. The Parties agree that any action or proceeding arising out of or related to this Agreement shall be brought exclusively in the state or federal courts located in {{venue_county}} County, Texas. Each Party irrevocably submits to the exclusive personal jurisdiction of such courts and waives any objection to venue in such courts.\n\n13.3 Texas Business & Commerce Code. This Agreement shall be interpreted consistently with applicable provisions of the Texas Business & Commerce Code, including Chapter 35 (relating to prompt payment) and Chapter 322 (Uniform Electronic Transactions Act).\n\n13.4 Texas Franchise Tax Acknowledgment. If either Party is a taxable entity under Texas Tax Code Chapter 171 (Texas Franchise Tax), such Party shall be solely responsible for its own Texas franchise tax obligations. Neither Party makes any representation or warranty regarding the other Party''s franchise tax status or liability.\n\n13.5 Notices. All notices, requests, consents, and other communications under this Agreement must be in writing and shall be deemed given when: (a) delivered personally; (b) sent by confirmed email; (c) sent by nationally recognized overnight courier; or (d) mailed by certified mail, return receipt requested, postage prepaid.\n\nIf to Client: {{party_a_company}}, Attn: {{party_a_name}}, {{party_a_title}}, {{party_a_address}}, Email: {{party_a_email}}.\n\nIf to Consultant: {{party_b_company}}, Attn: {{party_b_name}}, {{party_b_title}}, {{party_b_address}}, Email: {{party_b_email}}.\n\n13.6 Assignment. Neither Party may assign or transfer this Agreement, in whole or in part, without the prior written consent of the other Party, except that Client may assign this Agreement without consent in connection with a merger, acquisition, corporate reorganization, or sale of substantially all of its assets, provided the assignee agrees in writing to be bound by the terms hereof.\n\n13.7 Subcontracting. Consultant may not subcontract any material portion of the Services without Client''s prior written consent. Consultant shall remain fully responsible for the performance of any approved subcontractors.\n\n13.8 Entire Agreement. This Agreement, together with any exhibits, statements of work, or attachments referenced herein, constitutes the entire agreement between the Parties with respect to the subject matter hereof and supersedes all prior and contemporaneous agreements, proposals, negotiations, representations, and understandings, whether written or oral.\n\n13.9 Amendment and Waiver. This Agreement may not be amended or modified except by a written instrument signed by authorized representatives of both Parties. No waiver of any right or remedy hereunder shall be effective unless in writing and signed by the waiving Party. No single or partial exercise of any right or remedy shall preclude any other or further exercise thereof or the exercise of any other right or remedy.\n\n13.10 Severability. If any provision of this Agreement is held invalid, illegal, or unenforceable by a court of competent jurisdiction, the remaining provisions shall remain in full force and effect. The Parties shall negotiate in good faith to replace any invalid provision with a valid provision that most closely reflects the original intent.\n\n13.11 Counterparts and Electronic Signatures. This Agreement may be executed in one or more counterparts, each of which shall be deemed an original and all of which together shall constitute one instrument. Signatures delivered electronically (including PDF, DocuSign, or other e-signature platforms) shall be valid and binding in accordance with Texas Business & Commerce Code Chapter 322 (Uniform Electronic Transactions Act).\n\n13.12 Force Majeure. Neither Party shall be liable for any delay or failure to perform due to causes beyond its reasonable control, including acts of God, natural disasters, epidemic, pandemic, war, terrorism, civil unrest, labor disputes, government action, or failures of third-party suppliers or networks (\"Force Majeure Event\"). The affected Party shall notify the other Party promptly and use reasonable efforts to mitigate the impact of the Force Majeure Event.\n\n13.13 Relationship of the Parties. The Parties are independent contracting parties. Nothing in this Agreement creates any partnership, joint venture, fiduciary relationship, employment relationship, or agency relationship.\n\n13.14 No Third-Party Beneficiaries. This Agreement is for the sole benefit of the Parties and their permitted successors and assigns. Nothing herein confers any rights on any third party.\n\n13.15 Interpretation. Section headings are for convenience only and shall not affect interpretation. The terms \"include,\" \"includes,\" and \"including\" shall be deemed to be followed by \"without limitation.\" References to \"days\" mean calendar days unless otherwise specified.\n\n13.16 Remedies Cumulative. Except as otherwise expressly provided herein, the rights and remedies under this Agreement are cumulative and in addition to any other rights and remedies available at law or in equity.\n\n13.17 Attorneys'' Fees. In any action or proceeding to enforce this Agreement, the prevailing Party shall be entitled to recover its reasonable attorneys'' fees and costs from the non-prevailing Party, in addition to any other relief to which it may be entitled.",
    "type": "standard",
    "order": 13
  }
